sys_security_acl.script:
// Allow if new record (so form loads)
if (current.isNewRecord()) {
    answer = true;
} else {

    // Allow if employee owns this record
    var emp = new GlideRecord('x_1954179_employ_0_employee');
    emp.addQuery('employee', gs.getUserID());
    emp.query();

    if (emp.next()) {
        answer = (current.employee == emp.sys_id)
                 || gs.hasRole('x_1954179_employ_0.admin');
    } else {
        answer = gs.hasRole('x_1954179_employ_0.admin');
    }
}
